// ─── Partner Tag Popup ────────────────────────────────────────────────────────
function PartnerTagPopup({ partner, onSave, onClose }) {
  const [selected, setSelected] = useState([...(partner.tags||[])])
  const toggle = id => setSelected(prev => prev.includes(id)?prev.filter(x=>x!==id):[...prev,id])
  return (
    <div style={{ position:'fixed', inset:0, zIndex:10003, display:'flex', alignItems:'flex-end', justifyContent:'center' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', borderRadius:'20px 20px 0 0', padding:'1rem', zIndex:1, boxShadow:'0 -8px 40px rgba(26,46,43,0.2)', boxSizing:'border-box', overflowX:'hidden' }}>
        <div style={{ width:'36px', height:'4px', background:'rgba(0,0,0,0.12)', borderRadius:'2px', margin:'0 auto 1rem' }} />
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'1rem' }}>
          <h3 style={{ fontSize:'16px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>Tags</h3>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'20px', color:'#8a9e9a', cursor:'pointer' }}>×</button>
        </div>
        <div style={{ display:'grid', gap:'7px', marginBottom:'1.25rem' }}>
          {PARTNER_TAGS.map(tag=>{
            const active = selected.includes(tag.id)
            return (
              <button key={tag.id} onClick={()=>toggle(tag.id)} style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'11px 14px', background:active?tag.bg:'white', border:`1.5px solid ${active?tag.color+'50':'rgba(0,0,0,0.08)'}`, borderRadius:'10px', cursor:'pointer', fontFamily:'inherit' }}>
                <span style={{ fontSize:'14px', fontWeight:500, color:active?tag.color:'#1a2e2b' }}>{tag.label}</span>
                <div style={{ width:'20px', height:'20px', borderRadius:'6px', border:`2px solid ${active?tag.color:'rgba(0,0,0,0.15)'}`, background:active?tag.color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>
                  {active&&<span style={{ fontSize:'11px', color:'white', fontWeight:700 }}>✓</span>}
                </div>
              </button>
            )
          })}
        </div>
        <div style={{ display:'flex', gap:'10px' }}>
          <button onClick={onClose} style={{ flex:1, padding:'11px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
          <button onClick={()=>onSave(selected)} style={{ flex:2, padding:'11px', background:'#1a2e2b', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:'white', cursor:'pointer' }}>Save Tags</button>
        </div>
      </div>
    </div>
  )
}

