          <button onClick={()=>text.trim()&&onAdd(text.trim())} disabled={!text.trim()} style={{ flex:2, padding:'11px', background:text.trim()?'#d4a046':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:text.trim()?'white':'#9ca3af', cursor:text.trim()?'pointer':'not-allowed' }}>🐝 Save Note</button>
