// ─── Partners Screen ──────────────────────────────────────────────────────────
// Exported for lib/network-saved-views.test.tsx (mount test — saved views
// must survive a remount). Not routed anywhere except App's nav.
export function PartnersScreen({ onNavigate, partners, setPartners, companies=[], setCompanies=()=>{}, onAddToHive, locFilter='all', isElevated=false, people=ALL_PEOPLE, initialSelected=null, onInitialSelectedConsumed=()=>{}, readOnly=false, setToast=()=>{}, locationRequired=false, onOpenLocationPicker=null, networkTruncated=false }) {
  if (!partners) return null
  // Phase 2 retired the Classic LIST (NetworkScreen renders the screen);
  // Phase 3 retired the Classic RECORDS — PartnerPanel + the inline company
  // overlay are replaced by NetworkPersonRecord / NetworkCompanyRecord
  // (§8.5 beta-chunk modules). This host is now only: the screen, the two
  // record overlays, and the two add modals. Writes still go through the
  // App-level CRM helpers (PartnersContext / CompaniesContext).
  const partnersApi  = useContext(PartnersContext)
  const companiesApi = useContext(CompaniesContext)
  const [selected, setSelected] = useState(initialSelected)
  React.useEffect(()=>{ if(initialSelected){ setSelected(initialSelected); onInitialSelectedConsumed() } },[initialSelected])
  // ONE add door (the merged NetworkAddSheet — Person/Company toggle
  // inside). addCompanyPreset = the company a new person is created INTO
  // (the company record's "+ Add person"); it forces the Person position.
  const [showAdd, setShowAdd] = useState(false)
  const [addCompanyPreset, setAddCompanyPreset] = useState(null)
  const [selectedCompany, setSelectedCompany] = useState(null)

  const allPartners = (locFilter==='all' ? partners : partners.filter(p=>p.locationId===locFilter)).filter(p=>!p.isDeleted)
  const allCompanies = locFilter==='all' ? companies : companies.filter(c=>c.locationId===locFilter)

  function updatePartner(updated) { partnersApi?.updatePartner ? partnersApi.updatePartner(updated) : setPartners(p=>p.map(x=>x.id===updated.id?updated:x)); setSelected(updated) }
  async function addPartner(p) { return partnersApi?.addPartner ? partnersApi.addPartner(p) : setPartners(prev=>[p,...prev]) }

  const openAdd = () => setShowAdd(true)

  return (
    <>
      <div style={{ fontFamily:'DM Sans,system-ui,sans-serif', background:'#f7f5f0', minHeight:'100vh', paddingBottom:'5rem' }}>
        <NetworkScreen
          partners={partners}
          companies={companies}
          locFilter={locFilter}
          specialties={getSpecialties().map(s=>({ id:s.id, label:s.label }))}
          readOnly={readOnly}
          onOpenPerson={(p)=>setSelected(p)}
          onOpenCompany={(c)=>setSelectedCompany(c)}
          onAdd={openAdd}
          locationRequired={locationRequired}
          onOpenLocationPicker={onOpenLocationPicker}
          truncated={networkTruncated}
        />
      </div>

      {/* Phase 3: the beta records replace Classic's PartnerPanel + inline
          company overlay (both retired-unrendered above in this file, like
          the Classic list). Person + company records are §8.5 modules; the
          host supplies state access + the CRM write paths. */}
      {selected&&(
        <NetworkPersonRecord
          partner={selected}
          companies={allCompanies}
          people={people}
          onClose={()=>setSelected(null)}
          onUpdate={(updated)=>updatePartner(updated)}
          onDelete={(id)=>{ partnersApi?.deletePartner ? partnersApi.deletePartner(id) : setPartners(prev=>prev.map(p=>p.id===id?{...p,isDeleted:true,deletedAt:new Date().toISOString()}:p)); setSelected(null) }}
          onOpenCompany={(c)=>{ setSelected(null); setSelectedCompany(c) }}
          setToast={setToast}
          readOnly={readOnly}
        />
      )}

      {selectedCompany&&(
        <NetworkCompanyRecord
          company={selectedCompany}
          partners={allPartners}
          onClose={()=>setSelectedCompany(null)}
          onUpdateCompany={(updated)=>{ companiesApi?.updateCompany ? companiesApi.updateCompany(updated) : setCompanies(prev=>prev.map(c=>c.id===updated.id?updated:c)); setSelectedCompany(updated) }}
          onOpenPerson={(p)=>{ setSelectedCompany(null); setSelected(p) }}
          onAddPerson={(co)=>{ setAddCompanyPreset(co); setShowAdd(true) }}
          onDelete={async (id)=>{ if (companiesApi?.deleteCompany) { await companiesApi.deleteCompany(id) } else { setCompanies(prev=>prev.filter(c=>c.id!==id)) } setSelectedCompany(null) }}
          setToast={setToast}
          readOnly={readOnly}
        />
      )}

      {/* ONE add door — the merged NetworkAddSheet (Person/Company toggle
          inside, beta shell). Replaces AddPartnerModal + AddCompanyModal,
          both retained-unrendered for the retired Classic callers. The
          admin picklists ride as props (§8.5 — the sheet can't reach the
          getters). */}
      {showAdd&&(
        <NetworkAddSheet
          onClose={()=>{ setShowAdd(false); setAddCompanyPreset(null) }}
          onAddPerson={addPartner}
          onAddCompany={(co)=>companiesApi?.addCompany ? companiesApi.addCompany(co) : Promise.resolve(null)}
          onUpdatePartner={updatePartner}
          partners={allPartners}
          companies={allCompanies}
          specialties={getSpecialties().map(s=>({ id:s.id, label:s.label }))}
          tiers={getPartnerTiers().map(t=>({ id:t.id, label:t.label }))}
          defaultCompany={addCompanyPreset}
        />
      )}
    </>
  )
}


