// (Card-format helpers removed with the fake card forms — checkout is
// Stripe-hosted; Bee Hub never renders a card field.)

function calcProration(annualRate) {
  const now   = new Date('2026-05-05')
  const renew = new Date('2027-03-01')
  const days  = Math.round((renew - now) / (1000*60*60*24))
  const prorated = Math.round(annualRate * (days/365))
  return { days, prorated, annual:annualRate, renewDate:'March 1, 2027' }
}

function withCC(amount) { return Math.round(amount * 1.03 * 100) / 100 }

