        <div style={{ width:'56px', height:'56px', borderRadius:'16px', background:'linear-gradient(135deg,#1a2e2b,#2d4f4a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', margin:'0 auto 16px' }}>📊</div>
